	auto &list_pr = parse_result.Cast<ListParseResult>();
	auto table_ref = transformer.Transform<unique_ptr<TableRef>>(list_pr.GetChild(1));
	auto result = TransformMergeIntoUsingClause(transformer, std::move(table_ref));
